const wb = $('Webhook').first().json.body;
const date = wb.date || new Date().toISOString().split('T')[0];
const meetingName = wb.meeting_name || 'Meeting';
const safeName = meetingName.replace(/[\/\\:*?"<>|]/g, '-');
const extractPath = $('Build Extract Note Body').first().json.extractPath || '';

// Extract response from the LLM
const extract = $('Generate Key Items').first().json.response || '';

// Parse ## Action Items section
const apMatch = extract.match(/##\s*Action Items\s*\n([\s\S]*?)(?:\n##|\n---|\s*$)/);
let apLines = [];
if (apMatch) {
  const section = apMatch[1];
  apLines = section.split('\n').filter(l => l.trim().match(/^-\s+\*\*\*Action Point/));
}

if (apLines.length === 0) {
  return [{ json: { hasActions: false, actionItems: [], appendContent: '', date, meetingName } }];
}

// Build append content for Pending Actions.md
const sourceRef = extractPath ? `\n<!-- Source: [[${extractPath}]] -->` : '';
const header = `\n\n## ${date} — ${safeName}${sourceRef}\n\n`;
const appendContent = header + apLines.join('\n');

return [{ json: { hasActions: true, actionItems: apLines, appendContent, date, meetingName, count: apLines.length } }];
